from typing import List, Dict, Any
from leann.api import PassageManager
from pathlib import Path
import json

def find_passages_by_text_pattern(
    index_path: str,
    pattern: str,
    case_sensitive: bool = False
) -> List[Dict[str, Any]]:
    """Find all passages in an index whose text contains a specified pattern."""
    if not pattern:
        raise ValueError("pattern cannot be empty")

    index_file = Path(index_path)
    meta_path = index_file.parent / f"{index_file.stem}.meta.json"

    if not meta_path.exists():
        raise FileNotFoundError(f"Index metadata file not found at {meta_path}")

    pm = PassageManager(index_path)
    all_passages = pm.get_all_passages()

    matches = []
    for passage in all_passages:
        text = passage.text
        if case_sensitive:
            if pattern in text:
                matches.append(passage.to_dict())
        else:
            if pattern.lower() in text.lower():
                matches.append(passage.to_dict())

    return matches

