from collections import Counter, defaultdict

def get_index_statistics(index_path: str) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index."""
    path = Path(index_path)
    if not path.exists():
        raise FileNotFoundError(f"Index file not found: {index_path}")

    try:
        searcher = LeannSearcher(index_path)
        pm = searcher.passage_manager
        passages = pm.get_all_passages()

        total_passages = len(passages)
        metadata_fields = set()
        field_value_counts = defaultdict(Counter)

        for passage in passages:
            metadata = passage.metadata
            for field_name, value in metadata.items():
                metadata_fields.add(field_name)
                field_value_counts[field_name][value] += 1

        field_value_counts = {
            field: dict(counts) 
            for field, counts in field_value_counts.items()
        }

        return {
            "total_passages": total_passages,
            "metadata_fields": sorted(list(metadata_fields)),
            "field_value_counts": field_value_counts
        }
    except Exception as e:
        if "metadata" in str(e).lower() or "not found" in str(e).lower():
            raise FileNotFoundError(f"Index metadata file not found: {index_path}") from e
        raise

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields."""
    path = Path(index_path)
    if not path.exists():
        raise FileNotFoundError(f"Index file not found: {index_path}")

    try:
        searcher = LeannSearcher(index_path)
        pm = searcher.passage_manager
        passages = pm.get_all_passages()

        total_passages = len(passages)
        covered_passages = 0
        field_coverages = {}
        missing_fields = []

        all_fields_in_any_passage = set()
        for passage in passages:
            all_fields_in_any_passage.update(passage.metadata.keys())

        missing_fields = [field for field in required_fields 
                         if field not in all_fields_in_any_passage]

        for passage in passages:
            has_all_fields = True
            for field in required_fields:
                if field not in passage.metadata:
                    has_all_fields = False
                    break
            if has_all_fields:
                covered_passages += 1

        coverage_percentage = (covered_passages / total_passages * 100) if total_passages > 0 else 0

        for field in required_fields:
            field_coverages[field] = (
                (sum(1 for passage in passages if field in passage.metadata) / total_passages * 100)
                if total_passages > 0 
                else 0
            )

        return {
            "coverage_percentage": round(coverage_percentage, 2),
            "field_coverage": field_coverages,
            "missing_fields": missing_fields
        }
    except Exception as e:
        if "metadata" in str(e).lower() or "not found" in str(e).lower():
            raise FileNotFoundError(f"Index metadata file not found: {index_path}") from e
        raise

from typing import List, Dict, Any
from leann.api import LeannBuilder
from pathlib import Path

def build_index_from_text_file(
    text_file_path: str,
    index_path: str,
    metadata: Dict[str, Any] = None,
    backend_name: str = "hnsw"
) -> str:
    """Build a LEANN index from a single text file."""
    text_path = Path(text_file_path)
    index_path = Path(index_path)

    # Check if text file exists
    if not text_path.exists():
        raise FileNotFoundError(f"Text file not found: {text_file_path}")

    # Check if file is empty
    if text_path.stat().st_size == 0:
        raise ValueError("Text file is empty")

    # Read and validate file content
    try:
        with open(text_file_path, 'r', encoding='utf-8') as f:
            content = f.read()

        if not content.strip():
            raise ValueError("Text file is empty")
    except UnicodeDecodeError:
        # Handle potential encoding issues
        with open(text_file_path, 'r', encoding='latin-1') as f:
            content = f.read()
        if not content.strip():
            raise ValueError("Text file is empty")

    # Process file content into passages
    lines = content.splitlines()
    passages = []
    for line in lines:
        stripped_line = line.strip()
        if stripped_line:
            passage_data = {'text': stripped_line}
            if metadata is not None:
                passage_data['metadata'] = metadata
            passages.append(passage_data)

    if not passages:
        raise ValueError("No non-empty lines found in text file")

    # Build index using LEANN
    builder = LeannBuilder(backend_name=backend_name)
    for passage in passages:
        builder.add_passage(passage)
    builder.build_index(str(index_path))

    return str(index_path)
